Here's a simple JavaScript function to strip username and password from a URL:

```javascript
function stripCredentials(url) {
    try {
        const parsedUrl = new URL(url);
        const { searchParams } = parsedUrl;
        const credentials = searchParams.get('auth');
        if (credentials) {
            searchParams.delete('auth');
            return parsedUrl.toString();
        } else {
            const usernamePassword = url.match(/^(?:https?:\/\/)?([^:\/?#]+)(?:\/[^?#]*)?(?:\?[^#]*)?(?:#\/?.*)?/);
            if (usernamePassword) {
                const usernamePasswordArray = usernamePassword[1].split('@');
                if (usernamePasswordArray.length > 1) {
                    const username = usernamePasswordArray[0];
                    const password = usernamePasswordArray[1].split(':')[0];
                    return url.replace(`${username}:${password}@`, '');
                }
            }
        }
    } catch (error) {
        console.error(error);
    }
    return url;
}

